BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?client ?clientName ?supplier ?supplierName WHERE {
  ?dep rdf:type vocab:refine .
  {
    ?dep vocab:Dependency_client <http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::APS%20Requirements::Interface%20Requirements> .
    ?dep vocab:Dependency_supplier ?supplier .
    ?supplier vocab:NamedElement_name ?supplierName .
    BIND(<http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::APS%20Requirements::Interface%20Requirements> AS ?client)
  }
  UNION
  {
    ?dep vocab:Dependency_supplier <http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::APS%20Requirements::Interface%20Requirements> .
    ?dep vocab:Dependency_client ?client .
    ?client vocab:NamedElement_name ?clientName .
    BIND(<http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::APS%20Requirements::Interface%20Requirements> AS ?supplier)
  }
}
LIMIT 25

